output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(MAX(?count) AS ?maxAppearances) WHERE {
  {
    SELECT(COUNT(?gf) AS ?count) WHERE {
      ?gf wdt:P3842 wd:Q2521385 .
      ?gf wdt:P118 wd:Q193317 .
    }
  } UNION {
    SELECT(COUNT(?gf) AS ?count) WHERE {
      ?gf wdt:P3842 wd:Q249679 .
      ?gf wdt:P118 wd:Q193317 .
    }
  }
}

